// Derived from _yearly/_monthly fields above — exported separately for clarity
export const SEED_DISTRIBUTOR_TARGETS = SEED_DISTRIBUTORS.flatMap((d) =>
  d._monthly.map((target_revenue, i) => ({
    id: `dt-${d.id}-${i+1}`,
    distributor_id: d.id,
    fiscal_year: 2026,
    month: i + 1,
    target_revenue,
  })).filter((r) => r.target_revenue > 0)
)

export const SEED_YEARLY_TARGETS = SEED_DISTRIBUTORS
  .filter((d) => d._yearly > 0)
  .map((d) => ({
    id: `dyt-${d.id}`,
    distributor_id: d.id,
    fiscal_year: 2026,
    yearly_estimate: d._yearly,
  }))

